BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?child ?childName ?childType WHERE {
  ?elem vocab:NamedElement_name "APS" .
  ?elem rdf:type vocab:package .
  ?elem vocab:Element_ownedElement ?child .
  OPTIONAL { ?child vocab:NamedElement_name ?childName }
  OPTIONAL { ?child rdf:type ?childType }
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?elem ?name ?type ?description WHERE {
  ?elem vocab:NamedElement_name "APS Mission" .
  ?elem rdf:type ?type .
  OPTIONAL { ?elem vocab:Comment_body ?description }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
